$Root = "C:\Users\domin\OneDrive\Desktop\Immo-analyzer\frontend"

$ApiFile = "$Root\src\pages\api\assistent.ts"
if (Test-Path $ApiFile) {
    Remove-Item $ApiFile -Force
    Write-Host "OK  assistent.ts entfernt" -ForegroundColor Green
} else {
    Write-Host "INFO assistent.ts nicht gefunden" -ForegroundColor Cyan
}

foreach ($dir in @("$Root\src\pages\api", "$Root\src\pages")) {
    if ((Test-Path $dir) -and ((Get-ChildItem $dir -Force).Count -eq 0)) {
        Remove-Item $dir -Force
        Write-Host "OK  Leerer Ordner entfernt: $dir" -ForegroundColor Green
    }
}

$CompDir = "$Root\src\components\Assistent"
New-Item -ItemType Directory -Force -Path $CompDir | Out-Null
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$CompDir\index.tsx", $bytes)
Write-Host "OK  Vite-Komponente eingespielt" -ForegroundColor Green

$EnvFile = "$Root\.env.local"
$envContent = if (Test-Path $EnvFile) { Get-Content $EnvFile -Raw } else { "" }
if ($envContent -notmatch "VITE_ANTHROPIC_API_KEY") {
    Add-Content -Path $EnvFile -Value "`nVITE_ANTHROPIC_API_KEY=sk-ant-DEINEN-KEY-HIER-EINTRAGEN"
    Write-Host "OK  VITE_ANTHROPIC_API_KEY zu .env.local hinzugefuegt - Key eintragen!" -ForegroundColor Yellow
} else {
    Write-Host "INFO VITE_ANTHROPIC_API_KEY bereits vorhanden" -ForegroundColor Cyan
}

Write-Host ""
Write-Host "Fertig! Jetzt: npm run build" -ForegroundColor Green